namespace CourseCatalog.Models;

public class Department
{
    public int Id { get; set; }
    public string Name { get; set; } = string.Empty;
    public string Code { get; set; } = string.Empty;
    public string Description { get; set; } = string.Empty;
}

public class Instructor
{
    public int Id { get; set; }
    public string Name { get; set; } = string.Empty;
    public string Title { get; set; } = string.Empty;
    public string Bio { get; set; } = string.Empty;
    public string Email { get; set; } = string.Empty;
}

public class Course
{
    public int Id { get; set; }
    public string Title { get; set; } = string.Empty;
    public string Code { get; set; } = string.Empty;
    public string Description { get; set; } = string.Empty;
    public int Credits { get; set; }
    public string Schedule { get; set; } = string.Empty;
    public int DepartmentId { get; set; }
    public string DepartmentName { get; set; } = string.Empty;
    public Instructor Instructor { get; set; } = new();
    public bool IsFeatured { get; set; }
}

public class EnrollmentRequest
{
    public string StudentName { get; set; } = string.Empty;
    public string StudentId { get; set; } = string.Empty;
    public int CourseId { get; set; }
}

using CourseCatalog.Models;

namespace CourseCatalog.Services;

public class CatalogService
{
    private readonly List<Department> _departments;
    private readonly List<Course> _courses;
    private readonly List<EnrollmentRequest> _enrollments = new();

    public CatalogService()
    {
        _departments = new List<Department>
        {
            new() { Id = 1, Name = "Computer Science", Code = "CS", Description = "Study of computation, algorithms, and information systems." },
            new() { Id = 2, Name = "Mathematics", Code = "MATH", Description = "Study of numbers, structures, and patterns." },
            new() { Id = 3, Name = "Physics", Code = "PHYS", Description = "Study of matter, energy, and the fundamental forces of nature." },
            new() { Id = 4, Name = "English", Code = "ENG", Description = "Study of literature, writing, and language arts." },
            new() { Id = 5, Name = "History", Code = "HIST", Description = "Study of past events and civilizations." }
        };

        var instructors = new List<Instructor>
        {
            new() { Id = 1, Name = "Dr. Sarah Chen", Title = "Professor", Bio = "Dr. Chen has 15 years of experience in software engineering and distributed systems. She received her Ph.D. from MIT and has published over 40 papers.", Email = "s.chen@university.edu" },
            new() { Id = 2, Name = "Dr. James Miller", Title = "Associate Professor", Bio = "Dr. Miller specializes in algorithms and computational complexity. He is the author of two textbooks on data structures.", Email = "j.miller@university.edu" },
            new() { Id = 3, Name = "Dr. Emily Rodriguez", Title = "Professor", Bio = "Dr. Rodriguez is an expert in linear algebra and its applications in machine learning. She leads the Applied Mathematics Research Group.", Email = "e.rodriguez@university.edu" },
            new() { Id = 4, Name = "Dr. Michael Thompson", Title = "Associate Professor", Bio = "Dr. Thompson's research focuses on quantum mechanics and particle physics. He previously worked at CERN.", Email = "m.thompson@university.edu" },
            new() { Id = 5, Name = "Dr. Lisa Park", Title = "Professor", Bio = "Dr. Park is an acclaimed author and literary critic specializing in modern American literature.", Email = "l.park@university.edu" },
            new() { Id = 6, Name = "Dr. Robert Kim", Title = "Assistant Professor", Bio = "Dr. Kim researches early modern European history with a focus on the Renaissance period.", Email = "r.kim@university.edu" }
        };

        _courses = new List<Course>
        {
            new() { Id = 1, Title = "Introduction to Programming", Code = "CS 101", Description = "Learn the fundamentals of programming using Python. Topics include variables, control flow, functions, and basic data structures. No prior experience required.", Credits = 3, Schedule = "Mon/Wed/Fri 9:00–9:50 AM", DepartmentId = 1, DepartmentName = "Computer Science", Instructor = instructors[0], IsFeatured = true },
            new() { Id = 2, Title = "Data Structures & Algorithms", Code = "CS 201", Description = "Study of fundamental data structures (arrays, linked lists, trees, graphs) and algorithm design techniques (divide-and-conquer, dynamic programming, greedy algorithms).", Credits = 4, Schedule = "Tue/Thu 10:30 AM–12:00 PM", DepartmentId = 1, DepartmentName = "Computer Science", Instructor = instructors[1], IsFeatured = true },
            new() { Id = 3, Title = "Operating Systems", Code = "CS 301", Description = "Principles of operating system design including process management, memory management, file systems, and concurrency.", Credits = 4, Schedule = "Mon/Wed 2:00–3:30 PM", DepartmentId = 1, DepartmentName = "Computer Science", Instructor = instructors[0], IsFeatured = false },
            new() { Id = 4, Title = "Calculus I", Code = "MATH 151", Description = "Limits, derivatives, and integrals of single-variable functions. Applications to physics and engineering problems.", Credits = 4, Schedule = "Mon/Wed/Fri 10:00–10:50 AM", DepartmentId = 2, DepartmentName = "Mathematics", Instructor = instructors[2], IsFeatured = true },
            new() { Id = 5, Title = "Linear Algebra", Code = "MATH 220", Description = "Vectors, matrices, linear transformations, eigenvalues, and applications. Essential for computer science and engineering students.", Credits = 3, Schedule = "Tue/Thu 1:00–2:30 PM", DepartmentId = 2, DepartmentName = "Mathematics", Instructor = instructors[2], IsFeatured = false },
            new() { Id = 6, Title = "General Physics I", Code = "PHYS 101", Description = "Mechanics, thermodynamics, and waves. Includes weekly lab sessions. Calculus-based.", Credits = 4, Schedule = "Mon/Wed/Fri 11:00–11:50 AM + Thu Lab 2:00–4:00 PM", DepartmentId = 3, DepartmentName = "Physics", Instructor = instructors[3], IsFeatured = false },
            new() { Id = 7, Title = "Quantum Mechanics", Code = "PHYS 301", Description = "Introduction to quantum theory: wave functions, Schrödinger equation, hydrogen atom, and spin.", Credits = 3, Schedule = "Tue/Thu 9:00–10:30 AM", DepartmentId = 3, DepartmentName = "Physics", Instructor = instructors[3], IsFeatured = true },
            new() { Id = 8, Title = "American Literature", Code = "ENG 210", Description = "Survey of American literature from the colonial period to the present, with emphasis on major authors and literary movements.", Credits = 3, Schedule = "Mon/Wed 3:00–4:30 PM", DepartmentId = 4, DepartmentName = "English", Instructor = instructors[4], IsFeatured = false },
            new() { Id = 9, Title = "Creative Writing", Code = "ENG 250", Description = "Workshop-based course focusing on fiction and poetry writing. Students develop original works and provide peer feedback.", Credits = 3, Schedule = "Tue/Thu 3:00–4:30 PM", DepartmentId = 4, DepartmentName = "English", Instructor = instructors[4], IsFeatured = true },
            new() { Id = 10, Title = "World History to 1500", Code = "HIST 101", Description = "Survey of world civilizations from prehistory through the medieval period, covering major cultural, political, and economic developments.", Credits = 3, Schedule = "Mon/Wed/Fri 1:00–1:50 PM", DepartmentId = 5, DepartmentName = "History", Instructor = instructors[5], IsFeatured = false }
        };
    }

    public List<Department> GetDepartments() => _departments;

    public Department? GetDepartment(int id) => _departments.FirstOrDefault(d => d.Id == id);

    public List<Course> GetCourses(string? search = null, int? departmentId = null)
    {
        var query = _courses.AsEnumerable();

        if (departmentId.HasValue)
            query = query.Where(c => c.DepartmentId == departmentId.Value);

        if (!string.IsNullOrWhiteSpace(search))
        {
            var term = search.Trim().ToLowerInvariant();
            query = query.Where(c =>
                c.Title.Contains(term, StringComparison.OrdinalIgnoreCase) ||
                c.Code.Contains(term, StringComparison.OrdinalIgnoreCase) ||
                c.Instructor.Name.Contains(term, StringComparison.OrdinalIgnoreCase));
        }

        return query.ToList();
    }

    public List<Course> GetFeaturedCourses() => _courses.Where(c => c.IsFeatured).ToList();

    public Course? GetCourse(int id) => _courses.FirstOrDefault(c => c.Id == id);

    public void SubmitEnrollment(EnrollmentRequest request) => _enrollments.Add(request);
}

